<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: system-ui, -apple-system, sans-serif;
    background: #f5f7fa;
    color: #1a1a2e;
    line-height: 1.6;
    max-width: 800px;
    margin: 0 auto;
    padding: 24px 16px 48px;
  }

  h1 { font-size: 1.5rem; margin-bottom: 20px; text-align: center; }

  .card {
    background: #fff;
    border-radius: 8px;
    padding: 20px;
    margin-bottom: 20px;
    box-shadow: 0 1px 3px rgba(0,0,0,.08);
  }

  .card h2 { font-size: 1.1rem; margin-bottom: 14px; }

  form { display: flex; gap: 10px; align-items: flex-end; flex-wrap: wrap; }
  form > div { display: flex; flex-direction: column; gap: 4px; }
  label { font-size: .85rem; font-weight: 600; color: #333; }

  input, select {
    padding: 8px 10px;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: .95rem;
    background: #fff;
  }
  input:focus, select:focus { outline: none; border-color: #3b82f6; box-shadow: 0 0 0 2px rgba(59,130,246,.2); }

  button#add-expense {
    padding: 8px 18px;
    background: #3b82f6;
    color: #fff;
    border: none;
    border-radius: 4px;
    font-size: .95rem;
    cursor: pointer;
    white-space: nowrap;
  }
  button#add-expense:hover { background: #2563eb; }

  #form-error {
    color: #dc2626;
    font-size: .85rem;
    margin-top: 8px;
    min-height: 1.2em;
  }

  .summary-row { display: flex; justify-content: space-between; align-items: center; padding: 8px 0; border-bottom: 1px solid #eee; font-size: .95rem; }
  .summary-row:last-child { border-bottom: none; }
  #total { font-weight: 700; color: #3b82f6; }

  .cat-total { display: flex; justify-content: space-between; padding: 4px 0; font-size: .9rem; color: #555; }

  .filters { display: flex; gap: 10px; align-items: flex-end; flex-wrap: wrap; margin-bottom: 12px; }
  .filters > div { display: flex; flex-direction: column; gap: 4px; min-width: 130px; }

  #expense-list { list-style: none; }
  .expense {
    display: grid;
    grid-template-columns: 1fr auto;
    align-items: center;
    gap: 12px;
    padding: 10px 0;
    border-bottom: 1px solid #f0f0f0;
    font-size: .95rem;
  }
  .expense:last-child { border-bottom: none; }

  .exp-info { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
  .exp-amount { font-weight: 700; color: #dc2626; min-width: 80px; text-align: right; }
  .exp-cat, .exp-date { color: #555; }

  .exp-del {
    background: none;
    border: none;
    color: #999;
    cursor: pointer;
    font-size: 1.2rem;
    padding: 4px 8px;
    line-height: 1;
  }
  .exp-del:hover { color: #dc2626; }

  .empty-msg { text-align: center; color: #999; font-style: italic; padding: 20px 0; }
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<!-- Entry Form -->
<div class="card">
  <form id="expense-form" novalidate>
    <div><label for="amount">Amount ($)</label><input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00"/></div>
    <div><label for="category">Category</label><select id="category"><option value="groceries">groceries</option><option value="transport">transport</option><option value="bills">bills</option><option value="fun">fun</option></select></div>
    <div><label for="date">Date</label><input type="date" id="date"/></div>
    <div><label for="note">Note (optional)</label><input type="text" id="note" placeholder="Optional note"/></div>
    <button type="submit" id="add-expense">Add Expense</button>
  </form>
  <div id="form-error"></div>
</div>

<!-- Summary -->
<div class="card">
  <h2>Total: <span id="total">$0.00</span></h2>
  <div id="cat-summary"></div>
</div>

<!-- Filters -->
<div class="card">
  <h2>Filters</h2>
  <form class="filters" id="filter-form">
    <div><label for="filter-category">Category</label><select id="filter-category"><option value="all">All</option></select></div>
    <div><label for="filter-from">From</label><input type="date" id="filter-from"/></div>
    <div><label for="filter-to">To</label><input type="date" id="filter-to"/></div>
  </form>
</div>

<!-- List -->
<div class="card">
  <h2>Expenses</h2>
  <ul id="expense-list"></ul>
</div>

<script>
(function () {
  'use strict';

  const STORAGE_KEY = 'expense-tracker-data';

  // --- DOM refs ---
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const addBtn = document.getElementById('add-expense');
  const formError = document.getElementById('form-error');

  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  const expenseList = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const catSummary = document.getElementById('cat-summary');

  // --- Helpers ---
  function fmt(n) { return '$' + Number(n).toFixed(2); }

  function loadExpenses() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      return JSON.parse(raw);
    } catch (e) { return []; }
  }

  function saveExpenses(list) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(list));
  }

  // --- Validation ---
  function validateAmount(val) {
    if (val === '' || val === null || val === undefined) return 'Amount is required.';
    const num = Number(val);
    if (isNaN(num)) return 'Amount must be a valid number.';
    if (num <= 0) return 'Amount must be greater than zero.';
    return '';
  }

  function validateDate(val) {
    if (!val || val === '') return 'A date is required.';
    const d = new Date(val + 'T00:00:00');
    if (isNaN(d.getTime())) return 'Invalid date.';
    return '';
  }

  function showError(msg) { formError.textContent = msg; }
  function clearError() { formError.textContent = ''; }

  // --- Add Expense ---
  form.addEventListener('submit', function (e) {
    e.preventDefault();
    const amtErr = validateAmount(amountInput.value);
    if (amtErr) { showError(amtErr); return; }
    const dtErr = validateDate(dateInput.value);
    if (dtErr) { showError(dtErr); return; }

    clearError();
    const expense = {
      id: Date.now().toString() + Math.random().toString(36).slice(2, 7),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value,
      note: noteInput.value.trim(),
    };

    const list = loadExpenses();
    list.push(expense);
    saveExpenses(list);

    // Reset amount field only (per spec)
    amountInput.value = '';
    renderAll();
  });

  // --- Delete ---
  function deleteExpense(id) {
    let list = loadExpenses();
    list = list.filter(function (e) { return e.id !== id; });
    saveExpenses(list);
    renderAll();
  }

  // --- Filtering ---
  function getVisibleExpenses() {
    const list = loadExpenses();
    let filtered = [...list];

    const catFilter = filterCategory.value;
    if (catFilter !== 'all') {
      filtered = filtered.filter(function (e) { return e.category === catFilter; });
    }

    const fromVal = filterFrom.value || '';
    const toVal = filterTo.value || '';
    if (fromVal && toVal) {
      filtered = filtered.filter(function (e) {
        return e.date >= fromVal && e.date <= toVal;
      });
    } else if (fromVal) {
      filtered = filtered.filter(function (e) { return e.date >= fromVal; });
    } else if (toVal) {
      filtered = filtered.filter(function (e) { return e.date <= toVal; });
    }

    // Newest first
    filtered.sort(function (a, b) {
      const da = new Date(a.date + 'T00:00:00').getTime();
      const db = new Date(b.date + 'T00:00:00').getTime();
      return db - da;
    });

    return filtered;
  }

  // --- Render ---
  function renderAll() {
    const visible = getVisibleExpenses();
    renderList(visible);
    renderSummary(visible);
    updateFilterOptions();
  }

  function renderList(expenses) {
    expenseList.innerHTML = '';
    if (expenses.length === 0) {
      expenseList.innerHTML = '<li class="empty-msg">No expenses found.</li>';
      return;
    }
    expenses.forEach(function (e) {
      const li = document.createElement('li');
      li.className = 'expense';
      li.dataset.id = e.id;

      const info = document.createElement('div');
      info.className = 'exp-info';
      info.innerHTML =
        '<span class="exp-amount">' + fmt(e.amount) + '</span>' +
        '<span class="exp-cat">' + escapeHtml(e.category) + '</span>' +
        '<span class="exp-date">' + e.date + '</span>';

      if (e.note) {
        const noteSpan = document.createElement('span');
        noteSpan.className = 'exp-note';
        noteSpan.style.color = '#777';
        noteSpan.textContent = ' — ' + escapeHtml(e.note);
        info.appendChild(noteSpan);
      }

      const delBtn = document.createElement('button');
      delBtn.type = 'button';
      delBtn.className = 'exp-del';
      delBtn.innerHTML = '&times;';
      delBtn.title = 'Delete expense';
      delBtn.addEventListener('click', function () { deleteExpense(e.id); });

      li.appendChild(info);
      li.appendChild(delBtn);
      expenseList.appendChild(li);
    });
  }

  function renderSummary(expenses) {
    const total = expenses.reduce(function (sum, e) { return sum + e.amount; }, 0);
    totalEl.textContent = fmt(total);

    // Per-category totals for visible expenses only
    const cats = {};
    expenses.forEach(function (e) {
      if (!cats[e.category]) cats[e.category] = 0;
      cats[e.category] += e.amount;
    });

    catSummary.innerHTML = '';
    Object.keys(cats).forEach(function (cat) {
      const div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', cat);
      div.textContent = escapeHtml(cat) + ': ' + fmt(cats[cat]);
      catSummary.appendChild(div);
    });

    if (Object.keys(cats).length === 0) {
      catSummary.innerHTML = '';
    }
  }

  function updateFilterOptions() {
    const cats = ['groceries', 'transport', 'bills', 'fun'];
    filterCategory.innerHTML = '<option value="all">All</option>';
    cats.forEach(function (c) {
      const opt = document.createElement('option');
      opt.value = c;
      opt.textContent = c.charAt(0).toUpperCase() + c.slice(1);
      filterCategory.appendChild(opt);
    });

    // Set date range defaults to today's month if empty
    if (!filterFrom.value) {
      const now = new Date();
      const first = new Date(now.getFullYear(), now.getMonth(), 1);
      filterFrom.value = first.toISOString().slice(0, 10);
    }
    if (!filterTo.value) {
      const last = new Date(now.getFullYear(), now.getMonth() + 1, 0);
      filterTo.value = last.toISOString().slice(0, 10);
    }
  }

  // --- Event listeners for filters ---
  filterCategory.addEventListener('change', renderAll);
  filterFrom.addEventListener('input', renderAll);
  filterTo.addEventListener('input', renderAll);

  // --- Utilities ---
  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // --- Init ---
  updateFilterOptions();
  renderAll();
})();
</script>
</body>
</html>
